fn main() {
    // 标量类型
    // char 占 4 字节，可以表示任意 Unicode 字符，比如中文
    let a: i32 = 42;
    let b: f64 = 3.14;
    let c: bool = true;
    let d: char = '中';

    // 复合类型
    // 数组类型写作 [元素类型; 长度]，长度固定，所有元素同类型
    let arr: [i32; 3] = [1, 2, 3];
    // 元组可以混合不同类型，长度同样固定
    let tup: (i32, f64, &str) = (500, 6.4, "hello");

    println!(
        "整数: {}, 浮点数: {}, 布尔值: {}, 字符: {}",
        a, b, c, d
    );
    // 数组用下标访问，索引从 0 开始，越界会在运行时 panic
    println!("数组第二个元素: {}", arr[1]);
    println!("元组: {:?}", tup);
    // 元组用 .索引 访问，索引必须是字面量，不能是变量
    println!("元组第一个元素: {}", tup.0);

    // 数组切片
    // [1..] 表示从索引 1 到结尾，& 说明切片只是借用原数组
    let slice = &arr[1..];
    println!("切片: {:?}", slice);

    // 整数字面量
    // 0x 前缀是十六进制，0b 前缀是二进制，_ 是分隔符
    let hex = 0xff;
    let binary = 0b1010_1010;
    println!(
        "十六进制 0xff = {}, 二进制 0b1010_1010 = {}",
        hex, binary
    );
}

