        format!("@{}", self.username)
    }
}

// impl Trait 作参数：接受任何实现了 Summary 的类型，
// 是「泛型 + trait 约束」的语法糖
fn notify(item: &impl Summary) {
    println!("突发新闻! {}", item.summarize());
}

