}

impl Counter {
    fn new() -> Counter {
        Counter { count: 0 }
    }
}

// 只要实现 Iterator trait，自定义类型就能接入整个迭代器生态
impl Iterator for Counter {
    // 关联类型：声明每次迭代产出的元素类型
    type Item = u32;

    // next 返回 Some 表示还有值，返回 None 时迭代结束
    fn next(&mut self) -> Option<Self::Item> {
        if self.count < 5 {
            self.count += 1;
            Some(self.count)
        } else {
            None
        }
    }
}

