    // 不可变引用可以同时存在任意多个
    let r1 = &s3;
    let r2 = &s3;
    println!("r1: {}, r2: {}", r1, r2);

    // 可变借用
    let mut s4 = String::from("mut");
    {
        // 可变引用同一时刻只能有一个，用短作用域及时释放
        let r3 = &mut s4;
        r3.push_str("able");
    } // r3 在这里结束
    println!("s4: {}", s4);
}

