fn main() {
    // (语言, 相对执行时间, 一句话特点)
    let languages = vec![
        ("C", "≈1×", "性能标杆，但内存安全全靠程序员"),
        ("C++", "≈1×", "性能同级、抽象更强，风险依旧"),
        ("Rust", "≈1×", "无 GC 的内存安全，编译期消除整类 bug"),
        ("Go", "≈2×", "简单高效，但有 GC 开销"),
        ("Java", "≈2–3×", "生态庞大，JVM 与 GC 带来运行时成本"),
        ("JavaScript", "≈3–8×", "灵活但慢，动态类型错误只能在运行时暴露"),
        ("Python", "≈30–100×", "好写但慢，GIL 限制并行"),
    ];

    println!("{:<12}{:<14}{}", "语言", "相对执行时间", "特点");
    println!("{}", "-".repeat(56));
    for (name, speed, note) in &languages {
        println!("{:<12}{:<14}{}", name, speed, note);
    }

    println!("\n没有最好的语言，只有最合适的场景。");
}

